4	const BLOCKED_REQUEST_HEADERS = new Set([
5	  "authorization",
6	  "cookie",
7	  "host",
8	  "x-api-key",
9	  "x-auth-token",
10	  "content-length",
11	  "transfer-encoding",
12	]);
13	
14	const RESPONSE_HEADERS = ["content-type", "etag", "last-modified", "x-total-count"];
15	const DEFAULT_UPSTREAM_TIMEOUT_MS = 30_000;
16	
17	type NormalizedErrorType =
18	  | "missing_upstream_credentials"
19	  | "invalid_request"
20	  | "upstream_timeout"
21	  | "upstream_network_error"
22	  | "upstream_error";
23	
24	function normalizedError(type: NormalizedErrorType, service: ServiceDefinition, message: string, retryable = false): unknown {
25	  return {
26	    error: {
27	      type,
28	      service: service.id,
29	      message,
30	      retryable,
31	    },
32	  };
33	}
