35	function requiredTokenEnv(service: ServiceDefinition): string | undefined {
36	  if (service.auth.type === "bearer" || service.auth.type === "header" || service.auth.type === "prefixed") {
37	    return service.auth.tokenEnv;
38	  }
39	  return undefined;
40	}
41	
42	function serviceToken(service: ServiceDefinition): string {
43	  const tokenEnv = requiredTokenEnv(service);
44	  return tokenEnv ? process.env[tokenEnv] ?? "" : "";
45	}
46	
47	function authHeaders(service: ServiceDefinition): Record<string, string> {
48	  if (service.auth.type === "none") {
49	    return {};
50	  }
51	
52	  if (service.auth.type === "static") {
53	    return { [service.auth.headerName]: service.auth.value };
54	  }
55	
56	  const token = serviceToken(service);
57	
58	  if (!token) {
59	    return {};
60	  }
61	
62	  if (service.auth.type === "bearer") {
63	    return { Authorization: `Bearer ${token}` };
64	  }
65	
66	  if (service.auth.type === "header") {
67	    return { [service.auth.headerName]: token };
68	  }
69	
70	  return { Authorization: `${service.auth.prefix}${token}` };
71	}
72	
73	function cleanHeaders(headers: Record<string, string> | undefined): Record<string, string> {
74	  const cleaned: Record<string, string> = {};
75	
76	  for (const [name, value] of Object.entries(headers ?? {})) {
77	    if (BLOCKED_REQUEST_HEADERS.has(name.toLowerCase())) {
78	      continue;
79	    }
80	
81	    cleaned[name] = value;
82	  }
83	
84	  return cleaned;
85	}
