87	export function interpolatePath(path: string, pathParams: Record<string, string | number> = {}): string {
88	  return path.replace(/\{([^}]+)\}/g, (_match, key: string) => {
89	    const value = pathParams[key];
90	
91	    if (value === undefined || value === null) {
92	      throw new Error(`Missing required path parameter: ${key}`);
93	    }
94	
95	    return encodeURIComponent(String(value));
96	  });
97	}
