99	export function buildUrl(service: ServiceDefinition, input: ServiceRequestInput): URL {
100	  if (/^https?:\/\//i.test(input.path)) {
101	    throw new Error("Use relative paths only. Absolute URLs are not allowed.");
102	  }
103	
104	  const baseUrl = new URL(service.baseUrl);
105	  const base = baseUrl.href.endsWith("/") ? baseUrl.href : `${baseUrl.href}/`;
106	  const relativePath = input.path.replace(/^\/+/u, "");
107	  const url = new URL(relativePath, base);
108	
109	  if (url.origin !== baseUrl.origin) {
110	    throw new Error("Resolved URL escaped the configured service origin.");
111	  }
112	
113	  for (const [name, value] of Object.entries(input.query ?? {})) {
114	    if (Array.isArray(value)) {
115	      for (const item of value) {
116	        url.searchParams.append(name, String(item));
117	      }
118	    } else {
119	      url.searchParams.set(name, String(value));
120	    }
121	  }
122	
123	  return url;
124	}
125	
126	function usefulResponseHeaders(headers: Headers): Record<string, string> {
127	  const picked: Record<string, string> = {};
128	
129	  for (const name of RESPONSE_HEADERS) {
130	    const value = headers.get(name);
131	    if (value) {
132	      picked[name] = value;
133	    }
134	  }
135	
136	  return picked;
137	}
138	
139	function filterFields(data: unknown, fields: string[]): unknown {
140	  if (Array.isArray(data)) {
141	    return data.map((item) => filterFields(item, fields));
142	  }
143	
144	  if (data !== null && typeof data === "object") {
145	    const filtered: Record<string, unknown> = {};
146	    for (const field of fields) {
147	      if (field in data) {
148	        filtered[field] = (data as Record<string, unknown>)[field];
149	      }
150	    }
151	    return filtered;
152	  }
153	
154	  return data;
155	}
156	
157	function filterByDomain(data: unknown, domain: string): unknown {
158	  if (!Array.isArray(data)) {
159	    return data;
160	  }
161	
162	  const prefix = `${domain}.`;
163	  return data.filter((item) => {
164	    if (item !== null && typeof item === "object" && "entity_id" in item) {
165	      return String((item as Record<string, unknown>).entity_id).startsWith(prefix);
166	    }
167	    return false;
168	  });
169	}
170	
171	async function parseBody(response: Response): Promise<unknown> {
172	  const contentType = response.headers.get("content-type") ?? "";
173	  const text = await response.text();
174	
175	  if (!text) {
176	    return null;
177	  }
178	
179	  if (contentType.includes("application/json")) {
180	    try {
181	      return JSON.parse(text);
182	    } catch {
183	      return text;
184	    }
185	  }
186	
187	  return text;
188	}
