190	type MultipartScalar = string | number | boolean;
191	type MultipartBase64FileField = { _base64: string; filename: string; contentType?: string };
192	type MultipartBytesFileField = { _bytes: Uint8Array; filename: string; contentType?: string };
193	type MultipartFileField = MultipartBase64FileField | MultipartBytesFileField;
194	type MultipartField = MultipartScalar | MultipartScalar[] | MultipartFileField;
195	type MultipartBody = { _multipart: true } & Record<string, MultipartField | true>;
196	
197	function isFileField(value: unknown): value is MultipartFileField {
198	  return value !== null && typeof value === "object" && "filename" in value && ("_base64" in value || "_bytes" in value);
199	}
200	
201	function fileFieldBytes(value: MultipartFileField): Buffer {
202	  if ("_bytes" in value) {
203	    return Buffer.from(value._bytes);
204	  }
205	
206	  return Buffer.from(value._base64, "base64");
207	}
208	
209	export function isMultipartBody(body: unknown): body is MultipartBody {
210	  return body !== null && typeof body === "object" && "_multipart" in body && (body as Record<string, unknown>)["_multipart"] === true;
211	}
212	
213	function buildFormData(body: MultipartBody): FormData {
214	  const fd = new FormData();
215	
216	  for (const [key, value] of Object.entries(body)) {
217	    if (key === "_multipart") continue;
218	
219	    if (isFileField(value)) {
220	      const bytes = fileFieldBytes(value);
221	      const arrayBuffer = bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
222	      const blob = new Blob([arrayBuffer], { type: value.contentType ?? "application/octet-stream" });
223	      fd.append(key, blob, value.filename);
224	    } else if (Array.isArray(value)) {
225	      for (const item of value) {
226	        fd.append(key, String(item));
227	      }
228	    } else {
229	      fd.append(key, String(value));
230	    }
231	  }
232	
233	  return fd;
234	}
235	
236	export type CallServiceOptions = {
237	  timeoutMs?: number;
238	  operationId?: string;
239	};
240	
241	export async function callService(
242	  service: ServiceDefinition,
243	  input: ServiceRequestInput,
244	  options: CallServiceOptions = {},
245	): Promise<unknown> {
246	  const startedAt = performance.now();
247	  let url: URL;
248	
249	  try {
250	    url = buildUrl(service, input);
251	  } catch (error) {
252	    return normalizedError("invalid_request", service, error instanceof Error ? error.message : "Invalid request.");
253	  }
254	
255	  const tokenEnv = requiredTokenEnv(service);
256	  if (tokenEnv && !serviceToken(service)) {
257	    return normalizedError("missing_upstream_credentials", service, `Missing required credential environment variable: ${tokenEnv}`);
258	  }
259	
260	  const headers: Record<string, string> = {
261	    Accept: "application/json, text/plain;q=0.9, */*;q=0.8",
262	    ...cleanHeaders(input.headers),
263	    ...authHeaders(service),
264	  };
265	
266	  let body: BodyInit | undefined;
267	
268	  if (input.body !== undefined && input.method !== "GET") {
269	    if (isMultipartBody(input.body)) {
270	      body = buildFormData(input.body);
271	    } else {
272	      body = typeof input.body === "string" ? input.body : JSON.stringify(input.body);
273	      headers["Content-Type"] ??= "application/json";
274	    }
275	  }
276	
277	  const timeoutMs = options.timeoutMs ?? DEFAULT_UPSTREAM_TIMEOUT_MS;
278	  const controller = new AbortController();
279	  const timeout = setTimeout(() => controller.abort(), timeoutMs);
280	
281	  log("info", "upstream_request_started", {
282	    service: service.id,
283	    operationId: options.operationId,
284	    method: input.method,
285	    path: url.pathname,
286	  });
287	
288	  try {
289	    const response = await fetch(url, {
290	      method: input.method,
291	      headers,
292	      body,
293	      signal: controller.signal,
294	    });
295	
296	    let responseBody = await parseBody(response);
297	
298	    if (input.fields && Array.isArray(input.fields) && input.fields.length > 0) {
299	      responseBody = filterFields(responseBody, input.fields);
300	    }
301	
302	    if (input.domain) {
303	      responseBody = filterByDomain(responseBody, input.domain);
304	    }
305	
306	    const durationMs = Math.round(performance.now() - startedAt);
307	    log(response.ok ? "info" : "error", "upstream_request_finished", {
308	      service: service.id,
309	      operationId: options.operationId,
310	      method: input.method,
311	      path: url.pathname,
312	      status: response.status,
313	      durationMs,
314	    });
315	
316	    return {
317	      service: service.id,
318	      request: {
319	        method: input.method,
320	        url: `${url.pathname}${url.search}`,
321	      },
322	      response: {
323	        ok: response.ok,
324	        status: response.status,
325	        statusText: response.statusText,
326	        headers: usefulResponseHeaders(response.headers),
327	        body: responseBody,
328	      },
329	      ...(response.ok
330	        ? {}
331	        : {
332	            error: {
333	              type: "upstream_error",
334	              service: service.id,
335	              message: `Upstream responded with HTTP ${response.status}.`,
336	              retryable: response.status >= 500,
337	            },
338	          }),
339	    };
340	  } catch (error) {
341	    const durationMs = Math.round(performance.now() - startedAt);
342	    const aborted = controller.signal.aborted;
343	    log("error", "upstream_request_failed", {
344	      service: service.id,
345	      operationId: options.operationId,
346	      method: input.method,
347	      path: url.pathname,
348	      durationMs,
349	      error: error instanceof Error ? error.message : String(error),
350	      timeout: aborted,
351	    });
352	
353	    return normalizedError(
354	      aborted ? "upstream_timeout" : "upstream_network_error",
355	      service,
356	      aborted ? `Upstream request exceeded ${timeoutMs}ms.` : error instanceof Error ? error.message : "Upstream request failed.",
357	      true,
358	    );
359	  } finally {
360	    clearTimeout(timeout);
361	  }
362	}
