import type { ServiceDefinition } from "./services.js";
import { serviceFromRegistryEntry, SERVICE_REGISTRY } from "./serviceRegistry.js";

function readEnv(name: string, fallback?: string): string {
  return process.env[name] ?? fallback ?? "";
}

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function readNumberEnv(name: string, fallback: number): number {
  const raw = readEnv(name);
  if (!raw) return fallback;

  const value = Number(raw);
  if (!Number.isFinite(value) || value <= 0) {
    throw new Error(`${name} must be a positive number.`);
  }

  return value;
}

export type AppConfig = {
  port: number;
  publicUrl?: string;
  iconUrl: string;
  accessToken: string;
  corsOrigin?: string;
  upstreamTimeoutMs: number;
  services: ServiceDefinition[];
};

export function loadConfig(): AppConfig {
  const services = SERVICE_REGISTRY.map((entry) => serviceFromRegistryEntry(entry, readEnv)).filter(
    (service): service is ServiceDefinition => service !== undefined,
  );

  return {
    port: readNumberEnv("MCP_PORT", 3010),
    publicUrl: readEnv("MCP_PUBLIC_URL") || undefined,
    iconUrl: readEnv("MCP_ICON_URL", "https://cdn.jsdelivr.net/gh/selfhst/icons/png/mcphub.png"),
    accessToken: requireEnv("MCP_ACCESS_TOKEN"),
    corsOrigin: readEnv("MCP_CORS_ORIGIN") || undefined,
    upstreamTimeoutMs: readNumberEnv("MCP_UPSTREAM_TIMEOUT_MS", 30_000),
    services,
  };
}

input.content:
# Plan: Timeouts Dinámicos + Correlation IDs + Health Checks

## Resumen

Tres mejoras independientes al servidor `vmhq-mcp`. Se implementan en orden de menor a mayor complejidad. Cada feature pasa los gates de corrección (`bun run typecheck` y `bun test`) antes de continuar.

---

## Feature 1 — Timeouts Dinámicos por Servicio

**Problema:** `DEFAULT_UPSTREAM_TIMEOUT_MS = 30_000` es global. Proxmox puede tardar 60–120 s en operaciones de VM (snapshot, clone). Actualmente esas operaciones siempre fallan con `upstream_timeout`.

### Cambios

#### `src/services.ts`
Añadir campo opcional a `ServiceDefinition`:
```diff
 export type ServiceDefinition = {
   id: ServiceId;
   title: string;
   baseUrl: string;
   auth: ServiceAuth;
   defaultPathPrefix: string;
   defaultPathParams?: Record<string, string>;
+  timeoutMs?: number;
 };
```

#### `src/serviceRegistry.ts`
Añadir campo a `ServiceRegistryEntry` y configurarlo para Proxmox:
```diff
 export type ServiceRegistryEntry = {
   ...
+  timeoutMs?: number;
 };

 // En el array SERVICE_REGISTRY, entrada de Proxmox:
 {
   id: "proxmox",
   ...
+  timeoutMs: 120_000,
 },
```

Propagar el campo en `serviceFromRegistryEntry`:
```diff
 return {
   id: entry.id,
   title: entry.title,
   baseUrl,
   auth,
   defaultPathPrefix: entry.defaultPathPrefix,
   defaultPathParams: entry.defaultPathParams?.(readEnv),
+  timeoutMs: entry.timeoutMs,
 };
```

#### `src/mcp.ts`
En cada llamada a `callService`, preferir el timeout del servicio sobre el global:
```diff
-  { timeoutMs: upstreamTimeoutMs, operationId: endpoint.operationId }
+  { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, operationId: endpoint.operationId }
```
Aplica en `*_operation`, `*_request`, y `paperless_upload_finish` (3 sitios).

**Sin cambios en `.env.example` ni `README.md`** — el timeout de Proxmox es un default razonable, no configurable por env.

---

## Feature 2 — Correlation ID en Logs

**Problema:** Imposible rastrear qué llamadas a upstream corresponden a una sesión de agente específica cuando hay varios clientes activos.

### Diseño

- Generar un `requestId` (UUID corto: primeros 8 chars de `crypto.randomUUID()`) **una vez por request HTTP** en `index.ts`.
- Propagarlo como parámetro hasta `callService` vía `CallServiceOptions`.
- Incluirlo en **todos** los eventos de log de `serviceClient.ts`.
- Loguear también `requestId` en los eventos `http_request_started` / `mcp_request_finished` de `index.ts`.

### Cambios

#### `src/serviceClient.ts`
```diff
 export type CallServiceOptions = {
   timeoutMs?: number;
   operationId?: string;
+  requestId?: string;
 };
```

Añadir `requestId` a cada llamada a `log()` dentro de `callService`:
```diff
 log("info", "upstream_request_started", {
   service: service.id,
   operationId: options.operationId,
+  requestId: options.requestId,
   method: input.method,
   path: url.pathname,
 });
```
Igual para `upstream_request_finished` y `upstream_request_failed`.

#### `src/mcp.ts`
`createMcpServer` recibe un `requestId` opcional:
```diff
-export function createMcpServer(services: ServiceDefinition[], iconUrl: string, upstreamTimeoutMs = 30_000): McpServer {
+export function createMcpServer(services: ServiceDefinition[], iconUrl: string, upstreamTimeoutMs = 30_000, requestId?: string): McpServer {
```

Propagarlo en todas las llamadas a `callService`:
```diff
-  { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, operationId: endpoint.operationId }
+  { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, operationId: endpoint.operationId, requestId }
```

#### `src/index.ts`
Generar `requestId` al inicio del handler y pasarlo:
```diff
 async fetch(req) {
   const url = new URL(req.url);
   const startedAt = performance.now();
+  const requestId = crypto.randomUUID().slice(0, 8);

   log("debug", "http_request_started", {
     method: req.method,
     path: url.pathname,
+    requestId,
   });
   ...
-  const server = createMcpServer(config.services, config.iconUrl, config.upstreamTimeoutMs);
+  const server = createMcpServer(config.services, config.iconUrl, config.upstreamTimeoutMs, requestId);
   ...
   log("info", "mcp_request_finished", {
     method: req.method,
     path: url.pathname,
     status: response.status,
     durationMs: Math.round(performance.now() - startedAt),
+    requestId,
   });
```

**Resultado:** con `MCP_LOG_LEVEL=info` se puede filtrar `grep requestId=abc12345` para ver toda la cadena de un request.

---

## Feature 3 — Health Checks con Ping

**Problema:** `vmhq_status` solo verifica configuración (env var presente). No distingue "servicio configurado" de "servicio configurado y accesible".

### Diseño

- Añadir `pingPath?: string` a `ServiceRegistryEntry` y `ServiceDefinition` — la ruta barata a llamar para verificar liveness.
- Añadir parámetro `ping?: boolean` al tool `vmhq_status`.
- Si `ping: true`, hacer `GET pingPath` en paralelo para todos los servicios con timeout corto fijo de **3 000 ms** (independiente al timeout global).
- Retornar resultado por servicio: `{ status: "ok" | "error" | "timeout", httpStatus?, durationMs }`.

### Ping paths por servicio

| Servicio | `pingPath` |
|---|---|
| `home_assistant` | `/api/` |
| `miniflux` | `/v1/me` |
| `karakeep` | `/api/v1/lists` |
| `searxng` | `/` |
| `proxmox` | `/api2/json/version` |
| `memos` | `/api/v1/auth/status` |
| `nextdns` | `/profiles` |
| `paperless` | `/api/` |

### Cambios

#### `src/services.ts`
```diff
 export type ServiceDefinition = {
   ...
+  pingPath?: string;
 };
```

#### `src/serviceRegistry.ts`
```diff
 export type ServiceRegistryEntry = {
   ...
+  pingPath?: string;
 };

 // Añadir pingPath a cada entrada del SERVICE_REGISTRY
 { id: "home_assistant", pingPath: "/api/", ... },
 { id: "miniflux",       pingPath: "/v1/me", ... },
 // etc.
```

Propagar en `serviceFromRegistryEntry`:
```diff
+  pingPath: entry.pingPath,
```

#### `src/mcp.ts`
Schema del tool `vmhq_status`:
```diff
-  {},
+  { ping: z.boolean().optional().describe("If true, attempt a lightweight GET to each service to verify it is reachable. Uses a 3 s timeout.") },
```

Lógica del handler:
```typescript
async ({ ping }: { ping?: boolean }) => {
  const enabled = services.map((s) => s.id);
  const disabled = (Object.keys(API_CATALOGS) as ServiceId[])
    .filter((id) => !enabled.includes(id));

  let pingResults: Record<string, unknown> | undefined;

  if (ping) {
    const PING_TIMEOUT_MS = 3_000;
    const results = await Promise.all(
      services.map(async (service) => {
        if (!service.pingPath) {
          return [service.id, { status: "skipped", reason: "no_ping_path" }];
        }
        const start = performance.now();
        const result = await callService(
          service,
          { method: "GET", path: service.pingPath },
          { timeoutMs: PING_TIMEOUT_MS, operationId: "ping", requestId },
        );
        const durationMs = Math.round(performance.now() - start);
        const res = result as Record<string, unknown>;
        if (res.error) {
          const err = res.error as Record<string, unknown>;
          return [service.id, { status: err.type === "upstream_timeout" ? "timeout" : "error", durationMs }];
